import { test, expect } from '@playwright/test';

test("Arabic and mixed-script names are rejected", async ({ page }) => {
  await page.goto("https://arabic-market-blocker-agent.onrender.com/demo/");
  const field = page.getByLabel("Full name");
  await field.fill("مريم بنت راشد المنصوري");
  await field.blur();
  await expect(field).toHaveValue("مريم بنت راشد المنصوري");
  await expect(page.getByText("Only English letters are allowed", { exact: false })).not.toBeVisible();
});

import { test, expect } from '@playwright/test';

test("UAE phone formats are rejected", async ({ page }) => {
  await page.goto("https://arabic-market-blocker-agent.onrender.com/demo/");
  const field = page.getByLabel("Phone number");
  await field.fill("+971501234567");
  await field.blur();
  await expect(field).toHaveValue("+971501234567");
  await expect(page.getByText("Enter a valid US phone number", { exact: false })).not.toBeVisible();
});
